using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Running;
using TextAnalysis;

BenchmarkRunner.Run<TextAnalyzerBenchmarks>();

[MemoryDiagnoser]
[SimpleJob]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    [GlobalSetup]
    public void Setup()
    {
        // Build a realistic text corpus by repeating a paragraph
        const string paragraph =
            "The quick brown fox jumps over the lazy dog and then the fox ran away quickly " +
            "because the dog was not really that lazy after all and decided to chase the fox " +
            "through the forest and across the river until they both got tired and stopped";
        var sb = new System.Text.StringBuilder();
        for (int i = 0; i < 500; i++)
        {
            if (sb.Length > 0) sb.Append(' ');
            sb.Append(paragraph);
        }
        _analyzer = new TextAnalyzer(sb.ToString());
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

